    /**
     * Send an event using its integer ID for optimized O(1) dispatch.
     * This bypasses string-to-ID lookup for maximum performance.
     * @param {number} eventId - The event ID (use EVT_* constants)
     * @param {*} [data=null] - Optional event data
     */
    sendById(eventId, data = null) {
        if (this._finished) return;
        const eventName = this.getEventName(eventId);
        if (eventName === null) {
            console.warn('Unknown event ID:', eventId);
            return;
        }
        this.send(eventName, data);
    }

    _matchEvent(eventName, pattern) {
        if (pattern === '*' || pattern === '.*') return true;
        if (pattern === eventName) return true;

        // Prefix matching: 'foo' matches 'foo.bar'
        if (eventName.startsWith(pattern + '.')) return true;

        // Handle space-separated patterns
        const patterns = pattern.split(/\s+/);
        for (const p of patterns) {
            if (p === '*' || p === '.*') return true;
            if (p === eventName) return true;
            if (p.endsWith('.*') && eventName.startsWith(p.slice(0, -2))) return true;
            if (eventName.startsWith(p + '.')) return true;
        }

        return false;
    }

    /**
     * Check if an event ID matches a pattern (internal use).
     * Uses integer comparison for known events, falls back to string for unknown.
     */
    _matchEventById(eventId, eventName, patternId, pattern) {
        // Fast path: wildcard '*' matches everything
        if (pattern === '*' || pattern === '.*') return true;

        // Fast path: exact match by ID (for known events)
        if (eventId !== this.constructor.EVT_UNKNOWN && eventId === patternId) return true;

        // For unknown events or prefix matching, fall back to string comparison
        return this._matchEvent(eventName, pattern);
    }


